import json
import os
import re

# Load all business data
businesses_file = var_functions.query_db_40
businesses_data = []
if isinstance(businesses_file, str) and businesses_file.endswith('.json'):
    with open(businesses_file, 'r') as f:
        businesses_data = json.load(f)
else:
    businesses_data = businesses_file if isinstance(businesses_file, list) else []

# Create mapping from business_id to description
business_id_to_desc = {}
for business in businesses_data:
    if isinstance(business, dict) and 'business_id' in business:
        desc = business.get('description', '')
        business_id_to_desc[business['business_id']] = desc

print(f"Loaded {len(businesses_data)} businesses into mapping")

# Load reviews data
reviews_data = var_functions.query_db_38
if not isinstance(reviews_data, list):
    reviews_data = []

print(f"Loaded {len(reviews_data)} reviews from 2016-registered users")

# Extract categories and count reviews per category
category_review_counts = {}
business_to_categories = {}

for review in reviews_data:
    if isinstance(review, dict) and 'business_ref' in review:
        business_ref = review['business_ref']
        number = business_ref.split('_')[1]
        business_id = f'businessid_{number}'

        # Parse categories if not already done
        if business_id not in business_to_categories:
            categories = []
            if business_id in business_id_to_desc:
                desc = business_id_to_desc[business_id]

                # Try multiple patterns to extract categories
                patterns = [
                    r'(?:in|including|of|category of)\s+([A-Z][^,.]+(?:,\s*[A-Z][^,.]+)*)',
                    r'(?:fields of|categories of|range of services in)\s+([A-Z][^,.]+(?:,\s*[A-Z][^,.]+)*)',
                    r'(?:services, including|products in|specializes in)\s+([A-Z][^,.]+(?:,\s*[A-Z][^,.]+)*)',
                    r'(?:offers a (?:range|diverse (?:range|selection)) of[^.]*?in the (?:categories of|fields of)\s+([A-Z].*)|\boffers[^.]*?including\s+([A-Z][^,.]+(?:,\s*[A-Z][^,.]+)*))'
                ]

                found_categories = False
                for pattern in patterns:
                    matches = re.findall(pattern, desc, re.IGNORECASE)
                    if matches:
                        # Handle different match formats (sometimes groups)
                        for match in matches:
                            if isinstance(match, tuple):
                                # Take non-empty group
                                for group in match:
                                    if group:
                                        match = group
                                        break

                            if isinstance(match, str):
                                # Clean up the match
                                match = re.sub(r'\sand\s', ', ', match, flags=re.IGNORECASE)
                                # Split by comma and clean each category
                                for category in match.split(','):
                                    category = category.strip()
                                    # Skip common generic terms or empty strings
                                    if category and len(category) > 3 and not category.lower() in [
                                        'local services', 'food', 'restaurants', 'services',
                                        'products', 'establishment', 'facility', 'business',
                                        'range', 'selection', 'categories'
                                    ]:
                                        categories.append(category)
                                        found_categories = True

                                if found_categories:
                                    break

                        if found_categories:
                            break

                # If no pattern matched, try simpler approach
                if not found_categories and len(desc) < 200:
                    # Look for capitalized words sequences
                    simple_pattern = r'([A-Z][A-Za-z\s\&\-]+?)(?:,|\s+and\s+|\.)'
                    matches = re.findall(simple_pattern, desc)
                    for match in matches:
                        match = match.strip()
                        if (len(match) > 3 and ' ' in match and 
                            not any(x in match.lower() for x in [
                                'located at', 'this', 'offers', 'provides', 
                                'specializes', 'services', 'products'
                            ])):
                            categories.append(match)

            business_to_categories[business_id] = categories

        # Count reviews for each category
        categories = business_to_categories.get(business_id, [])
        for category in categories:
            category_review_counts[category] = category_review_counts.get(category, 0) + 1

print(f"Parsed categories for {len(business_to_categories)} businesses")
print(f"Found {len(category_review_counts)} unique categories")

# Get top 5 categories
top_5 = sorted(category_review_counts.items(), key=lambda x: x[1], reverse=True)[:5]
print(f"Top 5 categories:")
for category, count in top_5:
    print(f"  {category}: {count} reviews")

result = {
    "top_5_categories": top_5
}

print('__RESULT__:')
print(json.dumps(result))

